## Scenario 1: false positives under daily monitoring

The first simulation compares ordinary p-values checked daily with SAVI across
500 A/A tests. Each test runs for twenty days and adds 200 users per arm per
day. Both arms have a 10% conversion rate, so every rejection is a false
positive.

A test analyzed once at $\alpha = 0.05$ should reject in roughly 5 out of 100
null experiments. The figure shows the first 100 of the 500 simulations; all
500 are used in the summary table below. Each circle represents one experiment
and becomes a cross on the first day its method reports p < 0.05. If daily
monitoring preserved the 5% false positive rate, each panel would finish with
about five crosses. The experiments occupy the same positions in both panels,
so the methods are evaluated on the same data.

::: {#ebcb4e76 .cell execution_count=3}
``` {.python .cell-code code-fold="true" code-summary="Show the simulation code"}
mirage = _simulate_paths(p_control=0.10, p_treatment=0.10, seed=42)

fpr_single_look = (mirage["regular_p"][:, -1] <= ALPHA).mean()
fpr_daily_ordinary = (mirage["regular_p"] <= ALPHA).any(axis=1).mean()
fpr_daily_savi = (mirage["savi_p"] <= ALPHA).any(axis=1).mean()
```
:::


::: {#4729ad12 .cell execution_count=4}
``` {.python .cell-code code-fold="true" code-summary="Show the figure code"}
N_SHOWN = 100
EVIDENCE_BAR = -np.log10(ALPHA)

show_reg = mirage["regular_p"][:N_SHOWN]
show_savi = mirage["savi_p"][:N_SHOWN]
reg_stop = _stop_day(show_reg)
savi_stop = _stop_day(show_savi)

dot_x = np.tile(np.arange(1, 11), 10)
dot_y = np.repeat(np.arange(10, 0, -1), 10)


def _mirage_trace(stop, day, color):
    fired = (stop != 0) & (stop <= day)
    status = [
        f"False alarm on day {stop[i]}" if fired[i] else f"No false alarm by day {day}"
        for i in range(N_SHOWN)
    ]
    return go.Scatter(
        x=dot_x,
        y=dot_y,
        mode="markers",
        marker={
            "size": 11,
            "symbol": ["x" if value else "circle-open" for value in fired],
            "color": [
                color if value else _rgba(NEUTRAL_GREY, 0.45) for value in fired
            ],
            "line": {"width": 1.5},
        },
        customdata=np.arange(1, N_SHOWN + 1),
        text=status,
        hovertemplate="Experiment %{customdata}<br>%{text}<extra></extra>",
        showlegend=False,
    )


def _mirage_traces(day):
    return [
        _mirage_trace(reg_stop, day, ORDINARY_ORANGE),
        _mirage_trace(savi_stop, day, SAVI_BLUE),
    ]


def _mirage_title(day):
    n_reg = int(((reg_stop != 0) & (reg_stop <= day)).sum())
    n_savi = int(((savi_stop != 0) & (savi_stop <= day)).sum())
    return (
        f"Day {day}: false alarms so far"
        f"<br>Ordinary: {n_reg}/{N_SHOWN} · SAVI: {n_savi}/{N_SHOWN}"
    )


mirage_days = list(range(1, N_DAYS + 1))
fig = make_subplots(
    rows=2,
    cols=1,
    vertical_spacing=0.20,
    subplot_titles=(
        "Ordinary test, checked daily",
        "SAVI, checked daily",
    ),
)
for i, trace in enumerate(_mirage_traces(mirage_days[0])):
    fig.add_trace(trace, row=i + 1, col=1)

fig.frames = [
    go.Frame(
        data=_mirage_traces(day),
        traces=[0, 1],
        name=str(day),
        layout={"title": {"text": _mirage_title(day)}},
    )
    for day in mirage_days
]
fig.update_xaxes(visible=False, range=[0.3, 10.7])
fig.update_yaxes(visible=False, range=[0.4, 10.6])
fig.add_annotation(
    x=0.5,
    y=-0.06,
    xref="paper",
    yref="paper",
    text="○ no false alarm yet&nbsp;&nbsp;&nbsp;&nbsp;× false alarm",
    showarrow=False,
    font={"color": NEUTRAL_GREY},
)
fig.update_layout(
    title=_mirage_title(mirage_days[0]),
    title_font_size=16,
    template="plotly_white",
    height=640,
    updatemenus=PLAY_PAUSE,
    sliders=_slider(mirage_days, active=0),
    margin={"l": 45, "r": 30, "t": 120, "b": 155},
)
fig
