::: {#12c866e8 .cell execution_count=11}
``` {.python .cell-code code-fold="true" code-summary="Show the figure code"}
days = np.arange(1, MDE_MONITORING_DAYS + 1)
oneshot_curve = np.where(days >= N_DAYS, oneshot_power, 0.0)

fig = go.Figure()
fig.add_trace(
    go.Scatter(
        x=days,
        y=oneshot_curve,
        mode="lines+markers",
        line={"shape": "hv", "dash": "dash", "color": ORDINARY_ORANGE},
        name="Ordinary test, one look on day 20",
        hovertemplate="Day %{x}<br>Detected: %{y:.0%}<extra></extra>",
    )
)
fig.add_trace(
    go.Scatter(
        x=days,
        y=savi_detection,
        mode="lines+markers",
        line_color=SAVI_BLUE,
        name="SAVI, may continue after day 20",
        hovertemplate="Day %{x}<br>Detected by this day: %{y:.0%}<extra></extra>",
    )
)
fig.add_vline(
    x=N_DAYS,
    line_dash="dash",
    line_color=NEUTRAL_GREY,
